import { useEffect, useRef, useState } from "react";
import { clamp, ease } from "./helpers";

export default function TrustSection() {
  const sectionRef = useRef(null);
  const [p, setP] = useState(0);

  useEffect(() => {
    const onScroll = () => {
      const el = sectionRef.current;
      if (!el) return;

      const scrolled = Math.max(0, -el.getBoundingClientRect().top);
      const total = el.offsetHeight - window.innerHeight;
      const progress = scrolled / (total * 0.85); // slightly tighter timing

      setP(Math.max(0, Math.min(1, progress)));
    };

    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll();

    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const lp = (start, end) => ease(clamp((p - start) / (end - start), 0, 1));

  const ghost1 = lp(0.12, 0.42);   // left annotation
  const ghost2 = lp(0.48, 0.78);   // right annotation

  const serif = "'Playfair Display', 'Georgia', serif";

  return (
    <div 
      ref={sectionRef} 
      style={{ 
        height: "280vh", 
        position: "relative", 
        background: "#fff",
        overflow: "hidden"
      }}
    >
      <div style={{
        position: "sticky",
        top: 0,
        height: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        overflow: "hidden",
        padding: "0 5vw",
      }}>

        {/* Main Text Container */}
        <div style={{
          position: "relative",
          textAlign: "center",
          maxWidth: "1100px",
          zIndex: 1,
        }}>
          {/* Trust, */}
          <div style={{ marginBottom: "0.1em" }}>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(72px, 12vw, 160px)",
              fontWeight: 900,
              color: "#1a3a6b",
              lineHeight: 1,
              display: "block"
            }}>
              Trust,
            </span>
          </div>

          {/* however is fragile. */}
          <div style={{
            display: "flex",
            alignItems: "baseline",
            justifyContent: "center",
            gap: "0.25em",
            flexWrap: "wrap",
            marginBottom: "1.2rem"
          }}>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(52px, 9vw, 125px)",
              fontWeight: 400,
              color: "#999",
              lineHeight: 1.05,
            }}>
              however is
            </span>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(52px, 9vw, 125px)",
              fontWeight: 900,
              color: "#1a1a1a",
              lineHeight: 1.05,
            }}>
              fragile.
            </span>
          </div>

          {/* One news headline. */}
          <div style={{ marginBottom: "0.6rem" }}>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(42px, 7.5vw, 105px)",
              fontWeight: 900,
              color: "#e53e3e",
            }}>One </span>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(42px, 7.5vw, 105px)",
              fontWeight: 400,
              color: "#999",
            }}>
              news headline.
            </span>
          </div>

          {/* One breach */}
          <div style={{ marginBottom: "0.6rem" }}>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(42px, 7.5vw, 105px)",
              fontWeight: 900,
              color: "#e53e3e",
            }}>One </span>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(42px, 7.5vw, 105px)",
              fontWeight: 400,
              color: "#999",
            }}>
              breach
            </span>
          </div>

          {/* One bad experience */}
          <div style={{ marginBottom: "2.5rem" }}>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(42px, 7.5vw, 105px)",
              fontWeight: 900,
              color: "#e53e3e",
            }}>One </span>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(42px, 7.5vw, 105px)",
              fontWeight: 400,
              color: "#999",
            }}>
              bad experience
            </span>
          </div>

          {/* Final line */}
          <p style={{
            fontSize: "clamp(15px, 1.4vw, 21px)",
            color: "#555",
            lineHeight: 1.65,
            maxWidth: "620px",
            margin: "0 auto",
            fontFamily: "'Inter', system-ui, sans-serif"
          }}>
            is all it takes to undo years of hard-earned customer confidence.
          </p>
        </div>

        {/* Left Ghost Annotation (Peach tone - matches Figma) */}
        <div style={{
          position: "absolute",
          left: "12%",
          top: "38%",
          zIndex: 10,
          pointerEvents: "none",
          width: "340px",
          opacity: ghost1,
          transform: `translateY(${(1 - ghost1) * 140}px)`,
          background: "rgba(255, 235, 230, 0.92)",
          backdropFilter: "blur(14px)",
          WebkitBackdropFilter: "blur(14px)",
          borderRadius: "12px",
          padding: "20px 24px",
          boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
          border: "1px solid rgba(255,180,160,0.3)",
        }}>
          <p style={{
            fontSize: "14.5px",
            lineHeight: 1.75,
            color: "#222",
            fontFamily: "'Inter', sans-serif",
            margin: 0,
          }}>
            When speed and scale take priority, due diligence 
            slips and blind spots widen. That's exactly what is{" "}
            <span style={{ backgroundColor: "#ffe6e0", padding: "2px 4px", borderRadius: "3px" }}>
              happening in the gig economy today
            </span>.
          </p>
        </div>

        {/* Right Ghost Annotation (Cool tone) */}
        <div style={{
          position: "absolute",
          right: "9%",
          bottom: "24%",
          zIndex: 10,
          pointerEvents: "none",
          width: "360px",
          opacity: ghost2,
          transform: `translateY(${(1 - ghost2) * 130}px)`,
          background: "rgba(235, 242, 255, 0.92)",
          backdropFilter: "blur(14px)",
          WebkitBackdropFilter: "blur(14px)",
          borderRadius: "12px",
          padding: "20px 24px",
          boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
          border: "1px solid rgba(180,200,255,0.25)",
        }}>
          <p style={{
            fontSize: "14.5px",
            lineHeight: 1.75,
            color: "#222",
            fontFamily: "'Inter', sans-serif",
            margin: 0,
          }}>
            Identity swaps, impersonation, and hidden criminal 
            histories do more than disrupt operations. They put 
            safety, credibility, and customer trust at risk.
          </p>
        </div>
      </div>
    </div>
  );
}
